sql:
SELECT lag_period, performance_metric
FROM lag_analysis
WHERE sector = 'Healthcare';

SELECT equally_weighted, djia
FROM market_data
WHERE record_date = (SELECT MAX(record_date) FROM market_data);

SELECT index_name
FROM indices
WHERE index_id = 0;

SELECT index_name 
FROM indices 
WHERE index_type = 'Weighted';

SELECT user_name
FROM users
ORDER BY user_name;

external_knowledge:
- "golden peaks" metaphorically refers to the top records;
- "where the equally weighted index shines the brightest" means the highest values of the `equally_weighted` index;
- "identities and the dates marking these luminous moments" refer to `data_id` and `record_date`.

- 'sailors' refers to the users making investments; 
- 'technological ocean' refers to the 'Technology' sector of investments; 
- 'coordinates of their voyages' refers to investment details such as dates, amounts, and current values; 
- 'signposts' represent the performance metrics tied to each investment, specifically the most recent three entries for each user.

sql:
SELECT 
    (SELECT AVG(performance) FROM investments WHERE sector = 'Healthcare') AS avg_healthcare_performance,
    (SELECT AVG(performance) FROM investments) AS avg_all_performance;
